  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">1.617 Krypto-Verbraucherschiedsverfahren — Wie Sie Endeten</text>
  <g font-family="sans-serif">
    <text x="20" y="65" fill="#e4e4e7" font-size="13" font-weight="700">Durch Vergleich Beigelegt</text>
    <rect x="20" y="75" width="308" height="28" rx="6" fill="#3b82f6"/>
    <text x="338" y="95" fill="#93c5fd" font-size="13.5" font-weight="700">830 (51%)</text>

    <text x="20" y="125" fill="#e4e4e7" font-size="13" font-weight="700">Zurückgezogen / Aufgegeben</text>
    <rect x="20" y="135" width="164" height="28" rx="6" fill="#64748b"/>
    <text x="194" y="155" fill="#cbd5e1" font-size="13.5" font-weight="700">442 (27%)</text>

    <text x="20" y="185" fill="#e4e4e7" font-size="13" font-weight="700">Verwaltungstechnisch Geschlossen</text>
    <rect x="20" y="195" width="75" height="28" rx="6" fill="#64748b"/>
    <text x="105" y="215" fill="#cbd5e1" font-size="13.5" font-weight="700">202 (13%)</text>

    <text x="20" y="245" fill="#e4e4e7" font-size="13" font-weight="700">Zu Schiedsspruch Gelangt</text>
    <rect x="20" y="255" width="53" height="28" rx="6" fill="#a78bfa"/>
    <text x="83" y="275" fill="#ddd6fe" font-size="13.5" font-weight="700">143 (9%)</text>

